      <path d="M 60 70 L 54 12 L 50 3 L 50 70 Z" strokeWidth="2" fill="currentColor" fillOpacity="0.08" />
      
      {/* Fuller (Canaladura central que aligera la espada medieval) conectando con el acero */}
